VALUES
  ('pukao-6f0ba476-moex-00249', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-111-d35177eb', 'sub-pukao-6f0ba476-01', NULL, 'single_choice', '甲公司於X1年7月初以$250,000購入機器設備，估計耐用年限5年，無殘值，採成本模式後續 衡量並按直線法提列折舊。X2年底由於環境改變導致有重大跡象顯示該機器之價值已經減損，該 公司於X2年底作減損測試，估計該資產之使用價值為$148,000，公允價值減處分成本為$164,000。 X3 年初經公司重新評估後，估計耐用年限尚有 4 年，殘值不變，折舊方法改為年數合計法，則 X3年應認列之折舊為：', '["$38,500", "$41,000", "$50,000", "$65,600"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:45+00:00", "source_pdf_sha1": "e416025ce5d6", "answer_pdf_sha1": "02587aca6058", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "414", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00250', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-111-d35177eb', 'sub-pukao-6f0ba476-01', NULL, 'single_choice', '下列敘述，何者不屬於投資性不動產之項目？', '["為獲取長期資本增值，非供正常營業出售所持有之土地", "尚未決定未來用途所持有之土地", "企業擁有並以營業租賃出租之建築物", "持有供員工住宿用之建築物"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:45+00:00", "source_pdf_sha1": "e416025ce5d6", "answer_pdf_sha1": "02587aca6058", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "414", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00251', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-111-d35177eb', 'sub-pukao-6f0ba476-01', NULL, 'single_choice', '甲公司於X1年初購買設備$10,000,000，估計耐用年限8年、無殘值，採成本模式並以直線法提 列折舊。依照當地法規於 X8 年底除列該設備時須復原附近環境，該公司估計復原成本為 $2,000,000，折現至X1年初則為$933,015（折現率10%）。X1年度該公司需認列與此設備相關之 費用金額為何？（四捨五入至整數位）', '["$1,250,000", "$1,343,302", "$1,459,929", "$1,500,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:45+00:00", "source_pdf_sha1": "e416025ce5d6", "answer_pdf_sha1": "02587aca6058", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "414", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00252', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-111-d35177eb', 'sub-pukao-6f0ba476-01', NULL, 'single_choice', '有關負債準備之處理，下列敘述何者正確？', '["不須入帳，亦不須附註揭露", "不須入帳，但應附註揭露", "須估計入帳，並將之列為流動負債項下", "須估計入帳，並區分為流動負債或非流動負債"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:45+00:00", "source_pdf_sha1": "e416025ce5d6", "answer_pdf_sha1": "02587aca6058", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "414", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00253', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-111-d35177eb', 'sub-pukao-6f0ba476-01', NULL, 'single_choice', '甲公司設有零用金制度交由小明負責以支應日常零星開銷，零用金額度為$250。X1年7月31日 小明手上零用金剩$7 以及數張發票。發票包括進貨運費$88、郵資$45、排骨便當餐費$27、計程 車車資$65、比薩個人套餐餐費$20。該公司主管於撥補前發現在這些發票中，比薩個人套餐餐費 是小明的私人餐費，與公司支出無關。假設公司吸收多出來或是短少的零用金，下列有關零用金 撥補分錄何者正確？', '["借記零用金$245", "貸記現金短溢$17", "貸記銀行存款$243", "借記應收帳款$17 | 41630"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:45+00:00", "source_pdf_sha1": "e416025ce5d6", "answer_pdf_sha1": "02587aca6058", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "414", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00254', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-111-d35177eb', 'sub-pukao-6f0ba476-01', NULL, 'single_choice', '甲公司以現金支付當月份租金費用，會計人員誤將此交易登帳兩次，此行為對於結帳前試算表之', '["借方總額錯誤", "貸方總額正確", "借貸平衡", "借貸不平衡"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:45+00:00", "source_pdf_sha1": "e416025ce5d6", "answer_pdf_sha1": "02587aca6058", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "414", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00255', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-111-d35177eb', 'sub-pukao-6f0ba476-01', NULL, 'single_choice', '甲公司X1年1月1日權益組成如下： 普通股股本（面額$10） $30,000 特別股股本（面額$20，股利率6%） 60,000 資本公積-普通股發行溢價 22,000 資本公積-特別股發行溢價 45,000 保留盈餘 110,000 權益總額 $267,000 X1年與權益相關交易如下： 3/1 以每股$21買入600股庫藏股票 4/1 以每股$23賣出300股庫藏股票 7/1 宣告並發放普通股每股$3現金股利與$1股票股利及特別股股利，假設甲公 司普通股每股市價為$20 11/1 以每股$16賣出300股庫藏股票 12/31 甲公司X1年淨利$28,500 假設X1年甲公司無其他與權益相關之交易發生，則甲公司X1年保留盈餘的期末金額為多少？', '["$120,500", "$122,000", "$123,200", "$124,100"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:45+00:00", "source_pdf_sha1": "e416025ce5d6", "answer_pdf_sha1": "02587aca6058", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "414", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00256', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-111-d35177eb', 'sub-pukao-6f0ba476-01', NULL, 'single_choice', '甲公司擁有兩棟建築物A與B，均於X1年初取得，成本均為$10,000,000，估計耐用年限均為10 年，無殘值。該公司對於折舊之會計政策係採直線法。建築物A為營業場地使用，作為行政人員 上班以及公司銷售商品之處所；建築物B取得後隨即以每月租金$300,000出租。該公司選擇以公 允價值模式衡量非自用的不動產，X1年底兩棟建築物之公允價值均為$9,500,000。則X1年度兩 棟建築物對稅前淨利之影響為何？', '["$(2,000,000)", "$(1,500,000)", "$(1,200,000)", "$2,100,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:45+00:00", "source_pdf_sha1": "e416025ce5d6", "answer_pdf_sha1": "02587aca6058", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "414", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00257', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-111-d35177eb', 'sub-pukao-6f0ba476-01', NULL, 'single_choice', '甲公司於X2年期初應收帳款總額為$10,000，期末應收帳款總額為$16,000，X2年賒銷$40,000， 沖銷應收帳款$1,000，請問在計算X2年度來自營業活動之現金流量時，該等交易於間接法下之表 達及於直接法下應列報之銷貨收現數分別為何？', '["列報本期淨利加項$7,000；銷貨收現數$33,000", "列報本期淨利減項$7,000；銷貨收現數$33,000", "列報本期淨利加項$6,000；銷貨收現數$34,000", "列報本期淨利減項$6,000；銷貨收現數$34,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:45+00:00", "source_pdf_sha1": "e416025ce5d6", "answer_pdf_sha1": "02587aca6058", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "414", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00258', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-111-d35177eb', 'sub-pukao-6f0ba476-01', NULL, 'single_choice', '甲公司X1年度淨利為$800,000，X1年初以$2,000,000取得一棟供出租之商業大樓，採用成本模 式，X1年中由成本模式改為公允價值模式，後續衡量改變時該商業大樓之帳面金額為$1,800,000， X1年底公允價值為$2,000,000。請問甲公司X1年度「營業活動之淨現金流量」為多少？', '["$800,000", "$1,000,000", "$1,200,000", "$1,400,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:45+00:00", "source_pdf_sha1": "e416025ce5d6", "answer_pdf_sha1": "02587aca6058", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "414", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL)
